{"content":"package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"time"
)

// ANSI color codes
const (
	redBold   = "\033[31;1m"
	greenBold = "\033[32;1m"
	white     = "\033[37m"
	reset     = "\033[0m"
	blink     = "\033[5m"
)

// Score tracking
var (
	winsX int
	winsO int
	draws int
)

// clearScreen clears the terminal and moves cursor to home
func clearScreen() {
	fmt.Print("\033[2J\033[H")
}

// renderBoard prints the board with optional blinking on winning cells
func renderBoard(board [9]string, winIndices []int, blink bool) {
	// Score line
	fmt.Printf("Score: X: %d | O: %d | Draws: %d\n\n", winsX, winsO, draws)

	// Helper to get cell representation
	cell := func(idx int) string {
		val := board[idx]
		// Determine base color
		var base string
		if val == "X" {
			base = redBold
		} else if val == "O" {
			base = greenBold
		} else {
			base = white
		}
		// Apply blink if needed
		if blink {
			for _, w := range winIndices {
				if w == idx {
					base = blink + base
					break
				}
			}
		}
		return base + val + reset
	}

	// Row 0
	fmt.Printf(" %s | %s | %s \n", cell(0), cell(1), cell(2))
	fmt.Println("----------")
	// Row 1
	fmt.Printf(" %s | %s | %s \n", cell(3), cell(4), cell(5))
	fmt.Println("----------")
	// Row 2
	fmt.Printf(" %s | %s | %s \n\n", cell(6), cell(7), cell(8))
}

// checkWinner returns winner token and slice of winning indices if any
func checkWinner(board [9]string) (string, []int) {
	winPatterns := [][]int{
		{0, 1, 2}, // top row
		{3, 4, 5}, // middle row
		{6, 7, 8}, // bottom row
		{0, 3, 6}, // left col
		{1, 4, 7}, // middle col
		{2, 5, 8}, // right col
		{0, 4, 8}, // diagonal TL-BR
		{2, 4, 6}, // diagonal TR-BL
	}
	for _, pattern := range winPatterns {
		a, b, c := pattern[0], pattern[1], pattern[2]
		if board[a] != "1"+strconv.Itoa(a+1) && board[a] == board[b] && board[a] == board[c] {
			return board[a], pattern
		}
	}
	return "", nil
}

// isDraw returns true if board is full (no numbers left)
func isDraw(board [9]string) bool {
	for _, v := range board {
		if v != "X" && v != "O" {
			return false
		}
	}
	return true
}

// promptPlayer gets a valid move from the player using token
func promptPlayer(token string) int {
	in := bufio.NewReader(os.Stdin)
	for {
		var prompt string
		if token == "X" {
			prompt = "Player X's turn. Enter a number (1-9): "
		} else {
			prompt = "Player O's turn. Enter a number (1-9): "
		}
		fmt.Print(prompt)
		input, _ := in.ReadString('\n')
		input = strings.TrimSpace(input)
		pos, err := strconv.Atoi(input)
		if err != nil || pos < 1 || pos > 9 {
			fmt.Println("Invalid input. Please enter a number between 1 and 9.")
			continue
		}
		idx := pos - 1
		if board[idx] == "X" || board[idx] == "O" {
			fmt.Println("That space is already occupied. Choose another.")
			continue
		}
		return pos
	}
}

// playerX and playerO wrap promptPlayer
func playerX() int {
	return promptPlayer("X")
}
func playerO() int {
	return promptPlayer("O")
}

// playGame runs a single game session
func playGame() {
	board := [9]string{"1", "2", "3", "4", "5", "6", "7", "8", "9"}
	currentPlayer := "X"

	for {
		clearScreen()
		renderBoard(board, nil, false)

		var pos int
		if currentPlayer == "X" {
			pos = playerX()
		} else {
			pos = playerO()
		}

		idx := pos - 1
		if board[idx] == "X" || board[idx] == "O" {
			fmt.Println("That space is already occupied. Choose another.")
			time.Sleep(time.Second)
			continue
		}

		board[idx] = currentPlayer

		winner, winIndices := checkWinner(board)
		if winner != "" {
			clearScreen()
			renderBoard(board, winIndices, true)
			time.Sleep(3 * time.Second)
			clearScreen()
			renderBoard(board, winIndices, false)

			if winner == "X" {
				winsX++
				fmt.Printf("Player X wins!\n")
			} else {
				winsO++
				fmt.Printf("Player O wins!\n")
			}
			break
		}

		if isDraw(board) {
			clearScreen()
			renderBoard(board, nil, false)
			draws++
			fmt.Printf("It's a draw!\n")
			break
		}

		// Switch player
		if currentPlayer == "X" {
			currentPlayer = "O"
		} else {
			currentPlayer = "X"
		}
	}
}

// main loops games until user quits
func main() {
	for {
		playGame()
		fmt.Print("Play again? (y/n): ")
		in := bufio.NewReader(os.Stdin)
		answer, _ := in.ReadString('\n')
		answer = strings.TrimSpace(strings.ToLower(answer))
		if answer != "y" && answer != "yes" {
			fmt.Println("Thanks for playing!")
			break
		}
	}
